//P8767 [蓝桥杯 2021 国 A] 冰山
#include<bits/stdc++.h>
#define ll long long
#define int ll
#define fs first
#define se second
#define all(s) s.begin(), s.end()
#define pii pair<int, int>
using namespace std;
inline void cmax(int &a, int b){if(a < b)a = b;}
inline void cmin(int &a, int b){if(a > b)a = b;}
const int mod = 998244353;
void solve(){
	int n = 0, m = 0, k = 0;
	cin >> n >> m >> k;
	int tag = 0;
	int sum = 0, cnt = 0;
    map<int, int>mp;
	for(int i = 1; i <= n; i ++){
		int a; cin >> a;
		mp[a] ++; sum += a; cnt ++;
	}

	for(int iiop = 1; iiop <= m; iiop ++){
		int x, y;
		cin >> x >> y;
		tag += x;
		sum = (sum + cnt * x) % mod;
		for(auto it : mp){
			if(it.first + tag <= 0)
				sum = ((sum - (it.first + tag) * it.second) 
					% mod + mod) % mod, cnt -- ;
			else break;
            //mp.erase(mp.begin());
		}
		int cnt1 = 0, cntk = 0;
		if(!mp.empty()){
			auto it = prev(mp.end());
			while(!mp.empty() && (it -> first) + tag > k){
				cntk += it -> second;
				cnt1 += ((it -> first) + tag - k) * (it -> second);
				mp.erase(it -> first);
				if(mp.empty())break;
				it = prev(mp.end());
			}	
		}
		mp[y - tag] = (mp[y - tag] + 1) % mod;
		mp[1 - tag] = (mp[1 - tag] + cnt1)  % mod;
		mp[k - tag] = (mp[k - tag] + cntk) % mod;
		cnt += cnt1 + 1;
		cnt %= mod;
		sum = (sum + y) % mod;
		cout << sum << "\n";
	}
}
signed main(){
	ios :: sync_with_stdio(0);
	cin.tie(0), cout.tie(0);
//	freopen(".in", "r", stdin);
//	freopen(".out", "w", stdout);
	int T = 1;
//	cin >> T;
	while(T --){
		solve();
	}
}
